body.script:
// 
  const GAMES = ["snow-rider-3d","slope","1v1.lol","among-us","fnaf","cookie-clicker","fruit-ninja","subway-surfers","angry-birds","cut-the-rope","fireboy-and-watergirl","bloons-td-5","drift-boss","doodle-jump","2048","bitlife","backrooms","basketball-stars","bad-ice-cream","crossy-road","earn-to-die","flappy-bird","chess","rooftop-snipers","volley-random"];
  const emojiMap = {"snow-rider-3d":"🏔️","slope":"⛰️","1v1.lol":"🥅","among-us":"👾","fnaf":"🐻","cookie-clicker":"🍪","fruit-ninja":"🍉","fireboy-and-watergirl":"🔥💧","drift-boss":"🏎️","2048":"🔢","bitlife":"📱","backrooms":"🚪","chess":"♟️","flappy-bird":"🐦"};
  const grid = document.getElementById("gameGrid");
  const currentSpan = document.getElementById("currentGame");
  const statusDiv = document.getElementById("status");
  const reloadBtn = document.getElementById("reloadBtn");
  const container = document.getElementById("gameContainer");
  let currentAlias = "snow-rider-3d";

  function loadGame(alias) {
    currentAlias = alias;
    currentSpan.innerText = alias;
    statusDiv.innerHTML = "🎮 " + alias + " ...";

    // 1. Maak een nieuw, schoon iframe aan om memory leaks en oude scripts te voorkomen
    container.innerHTML = "";
    const iframe = document.createElement("iframe");
    container.appendChild(iframe);

    // 2. Verkrijg de document-context van het iframe
    const iframeDoc = iframe.contentWindow.document;

    // 3. Gebruik document.write om de <nex-game> tag en scripts binnen de iframe te genereren
    iframeDoc.open();
    iframeDoc.write(`
      <!DOCTYPE html>
      <html>
      <head>
        <style>
          html, body { margin: 0; padding: 0; width: 100%; height: 100%; overflow: hidden; background: #000; }
          nex-game { display: block; width: 100%; height: 100%; }
        </style>
        <script src="https://cdn.jsdelivr.net/gh/UseNex/nex-js@8ec0d5475baacc373a43c7afcc04442075b67f87/nex.min.js"><\/script>
      </head>
      <body>
        <nex-game id="innerPlayer" alias="${alias}" gid="sessie"></nex-game>
        <script>
          // Zorg ervoor dat het nex-script geladen is voordat we de sessie starten
          function startSessie() {
            if (window.nex && window.nex.sessie) {
              // Koppel de events terug naar de hoofd-document statusdiv
              window.nex.sessie.on("progress", function(d) {
                var p = Math.floor(d.progress * 100);
                parent.document.getElementById("status").innerHTML = "📦 ${alias} " + p + "%";
              });
              window.nex.sessie.on("ready", function() {
                parent.document.getElementById("status").innerHTML = "✅ ${alias} ready!";
                setTimeout(function() { 
                  if (window.nex.sessie) parent.document.getElementById("status").innerHTML = "⚡ ${alias}"; 
                }, 1500);
              });
              window.nex.sessie.on("error", function(e) {
                parent.document.getElementById("status").innerHTML = "❌ error: " + (e.message || "failed");
              });

              window.nex.sessie.start();
            } else {
              setTimeout(startSessie, 100);
            }
          }
          startSessie();
        <\/script>
      </body>
      </html>
    `);
    iframeDoc.close();
  }

  function buildGrid() {
    grid.innerHTML = "";
    for (let i = 0; i < GAMES.length; i++) {
      let g = GAMES[i];
      let emoji = emojiMap[g] || "🎮";
      let name = g.replace(/-/g, " ");
      let div = document.createElement("div");
      div.className = "card";
      div.setAttribute("data-game", g);
      div.innerHTML = '<span class="emoji">' + emoji + '</span><span class="name">' + name + '</span>';
      div.onclick = (function(game) { return function() { loadGame(game); }; })(g);
      grid.appendChild(div);
    }
  }

  reloadBtn.onclick = function() { loadGame(currentAlias); };

  buildGrid();
  loadGame("snow-rider-3d");
//
